import { NavLink } from "react-router-dom";
import { useAuth, hasRole } from "../AuthContext";

const item = (to, label, icon) => (
    <NavLink
        to={to}
        className={({ isActive }) =>
            "flex items-center gap-3 px-4 py-3 rounded-xl hover:bg-indigo-50 " +
            (isActive ? "bg-indigo-600 text-white hover:bg-indigo-600" : "text-slate-700")
        }
    >
    <span
        className={
            "w-6 h-6 grid place-content-center rounded " +
            (isActivePath(to) ? "bg-indigo-600 text-white" : "bg-indigo-100 text-indigo-700")
        }
    >
      {icon}
    </span>
        <span className="text-sm">{label}</span>
    </NavLink>
);

// helper để check isActive trong icon style
function isActivePath(to) {
    return window.location.pathname === to;
}

export default function Sidebar() {
    const { user } = useAuth();
    const isAdmin = hasRole(user, "ADMIN");
    const isSales = hasRole(user, "SALES");
    const isAcc = hasRole(user, "ACCOUNTANT");

    return (
        <aside className="w-72 bg-white/80 backdrop-blur shadow-xl border-r border-indigo-100 hidden lg:flex flex-col">
            <div className="p-6 border-b border-indigo-100">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-indigo-600 text-white grid place-content-center font-bold">
                        CT
                    </div>
                    <div className="font-bold text-slate-900">Quản lý KH & Hợp đồng</div>
                    {/* Bỏ dòng phụ “Bản React” */}
                </div>
            </div>

            <nav className="flex-1 overflow-auto p-3 space-y-2">
                {item("/dashboard", "Tổng quan", "🏠")}
                {(isAdmin || isSales) && item("/customers", "Khách hàng", "👥")}
                {(isAdmin || isSales || isAcc) && item("/contracts", "Hợp đồng", "📑")}
                {(isAdmin || isAcc) && item("/payments", "Thanh toán", "💳")}
                {(isAdmin || isSales) && item("/events", "Sự kiện", "📅")}
                {isAdmin && item("/users", "Người dùng", "🛠")}
                {(isAdmin || isAcc) && item("/reports", "Báo cáo", "📈")}
            </nav>

            {/* Bỏ footer thông báo JWT */}
            {/* <div className="p-4 border-t border-indigo-100 text-xs text-slate-500">
        Vai trò được áp theo JWT của bạn.
      </div> */}
        </aside>
    );
}
